import java.util.Arrays;
import java.util.Comparator;

public int minTimeOn(int[][] tasks) {
    int[][] intervals = new int[tasks.length][];
    for (int i = 0; i < tasks.length; i++) {
        intervals[i] = new int[] { tasks[i][1] + 1, tasks[i][2] };
    }
    Arrays.sort(intervals, Comparator.comparingInt(a -> a[0]));

    int[] dp = new int[2001];
    for (int[] interval : intervals) {
        for (int i = 2000; i >= interval[0]; i--) {
            dp[i] = Math.max(dp[i], dp[i - interval[1]] + interval[1]);
        }
    }
    return dp[2000];
}
```

